    public static function list($where = [], $page = 1, $limit = 10,  $order = [], $field = '', $options = [])
    {
        $model = new MerchantModel();
        $pk = $model->getPk();
        $supportsMemberSuper = self::supportsMemberSuperFlag();
        if (empty($field)) {
            // 闂傚倸鍊风粈渚€骞楀鍫濈獥閹肩补鍨惧☉妯滄棃宕担瑙勬珦闁诲骸绠嶉崕鍗灻洪妸锔锯枖鐎广儱顦伴悡銉︾箾閹寸伝顏堫敂椤忓牊鐓曞┑鐘插娴犻亶鏌＄仦鍓ф创妤犵偞甯￠獮娆撳礃閳哄啯姣岄梻鍌欑窔濞佳兾涘Δ鍛柈闁哄鍨归弳锕傛煥濠靛棭妯堥柡浣稿€块弻娑㈠箛閸忓摜鏁栧銈嗘⒐濡啫顫忛悜妯侯嚤婵炲棙鍨硅摫闂備浇宕甸崰鍡涘礉閹寸偘绻嗛柟缁㈠枛缁€鍐┿亜閺冨倸甯堕柛鐐姂濮婅櫣绱掑Ο璇茬濠电偞娼欓崲鏌モ€﹂崶顒€绫嶉柛灞剧矌閿涙粓姊洪柅鐐茶嫰婢у鈧娲﹂崑濠傜暦閻旂⒈鏁嗛柍褜鍓熼、鏃堫敍閻愮补鎷虹紓浣割儓濞夋洜绮绘导瀛樼厽闁靛牆鎳忔径鍕磼閸屾稑娴€规洖銈告俊鐑藉Ψ瑜滈崥瀣⒒娓氣偓閳ь剛鍋涢懟顖涙櫠鐎涙ü绻嗘い鎰剁磿缁愭棃鏌涢埞鎯т壕婵＄偑鍊栫敮鎺楀磹閻㈢纾婚柟鐐灱濡插牊绻涢崱妯曟垿鎮惧畡閭︽富闁靛牆妫欓悡銉╂煟椤撶偛鈧灝顕ｉ銏╁悑闁告侗鍨卞▓鏇㈡⒑閸涘﹥澶勫ù婊呭仧濡叉劕顫濋懜纰樻嫼缂備礁顑堝▔鏇犵不閹殿喚纾煎璺猴功娴犳稑菐閸パ嶈含鐎规洏鍔嶇换婵嬪磼濠婂懐宓侀梺鑽ゅ枑缁矂鏌婇敐鍜佸殨闁归棿绀佺粈鍐┿亜閺冨倸甯堕柣婵嚸—鍐Χ閸℃娼戦梺绋款儐閹瑰洭寮婚悢鍏兼啣闁稿本鑹剧粊顕€鎮楀▓鍨珮闁稿顦辩划璇测槈閵忕姵顥濋梺鍓茬厛閸燂綁濡舵径瀣幗闁瑰吋鐣崹濠氬煀閺囩喆浜滈柕濞垮劜椤ャ垺銇勯姀锛勬噮濞寸媴绠撳畷婊嗩槷闁哄鐗犲娲焻閻愯尪瀚板褎鎸抽弻锝呪槈閸楃偞鐝濋梺纭呮珪缁捇骞冩禒瀣棃婵炴垶顭囬崫妤呮⒒閸屾瑧顦﹂柟璇х節瀹曞綊鎳滈悽娈挎锤婵炲濮撮鍛存倿?
            $field = 'id,title,is_disable,create_time,username,address,phone,auth_state,auth_msg,sort,remark,name,image_id,member_id,expire_time,renew_remind_days,merchant_purchase_daily_quantity_limit,merchant_purchase_daily_amount_limit';
            if ($supportsMemberSuper) {
                $field .= ',member_is_super';
            }
        }
        if (empty($order)) {
            $order = ['sort'=>'asc',$pk => 'desc'];
        }
        $with     = [];
        $append   = [];
        $hidden   = [];
        if (strpos($field, 'member_id') !== false) {
            $with = ['member'=>function($query){
                $query->with(['avatar'])->append(['avatar_url'])->hidden(['avatar'])->field('member_id,nickname,avatar_id');
            }];
        }
        if (strpos($field, 'image_id') !== false) {
            $with[]   = $hidden[]   = 'image';
            $append[] = 'image_url';
            $append[] = 'receipt_image_url';
        }
        if ($page == 0 || $limit == 0) {
            return $model->with($with)->append($append)->hidden($hidden)->field($field)->where($where)->order($order)->select()->toArray();
        }
        $expireStatus = $options['expire_status'] ?? '';
        $query = $model->where($where);
        self::applyExpireStatusFilter($query, $expireStatus);
        $count = $query->count();
        $pages = ceil($count / $limit);
        $list = [];
        if ($count > 0) {
            $listQuery = $model->with($with)->append($append)->hidden($hidden)->field($field)->where($where);
            self::applyExpireStatusFilter($listQuery, $expireStatus);
            $list = $listQuery->page($page)->limit($limit)->order($order)->select()->toArray();
        }
        foreach ($list as $k => $v) {
            $list[$k] = self::appendExpireMeta($v);
            $list[$k]['auth_state_title'] = MerchantModel::getAuthState($v['auth_state'],2);
            $list[$k]['member_is_super'] = $supportsMemberSuper ? intval($v['member_is_super'] ?? 0) : 0;
            $list[$k]['member_is_super_title'] = intval($v['member_is_super'] ?? 0) === 1 ? '是' : '否';
            $list[$k] = MobileAdminAccessService::decorateMerchant($list[$k]);
        }
        $status_nums =self::getStatusNum(0);
        return compact('count', 'pages', 'page', 'limit', 'list','status_nums');
    }

    public static function renew($ids, $param = [])
    {
        $ids = array_values(array_filter(array_map('intval', (array) $ids)));
        if (empty($ids)) {
            exception('Please select merchants to update');
        }
        $renewMonths = intval($param['renew_months'] ?? 0);
        $renewDays = intval($param['renew_days'] ?? 0);
        if ($renewMonths === 0 && $renewDays === 0) {
            exception('Months and days cannot both be 0');
        }

        $amount = round(floatval($param['amount'] ?? 0), 2);
        $remark = trim((string) ($param['remark'] ?? ''));
        $renewRemindDays = self::normalizeRenewRemindDays($param['renew_remind_days'] ?? self::DEFAULT_RENEW_REMIND_DAYS);
        $operatorUid = intval(operate_user_id());
        $now = datetime();

        $merchantList = MerchantModel::whereIn('id', $ids)
            ->where('is_delete', 0)
            ->field('id,title,member_id,expire_time,renew_remind_days')
            ->select()
            ->toArray();
        if (empty($merchantList)) {
            exception('No merchants found');
        }

        Db::startTrans();
        try {
            $recordModel = new MerchantRenewRecordModel();
            foreach ($merchantList as $merchant) {
                $beforeExpireTime = $merchant['expire_time'] ?? null;
                if (self::isReduceAdjust($renewMonths, $renewDays) && empty($beforeExpireTime)) {
                    exception(($merchant['title'] ?? 'Merchant') . ' has no expire time, cannot reduce duration');
                }
                $afterExpireTime = self::calculateRenewExpireTime($beforeExpireTime, $renewMonths, $renewDays);
                MerchantModel::where('id', $merchant['id'])->update([
                    'expire_time' => $afterExpireTime,
                    'renew_remind_days' => $renewRemindDays,
                    'update_uid' => $operatorUid,
                    'update_time' => $now,
                ]);
                $recordModel->save([
                    'merchant_id' => $merchant['id'],
                    'member_id' => intval($merchant['member_id'] ?? 0),
                    'operator_uid' => $operatorUid,
                    'renew_source' => 'admin',
                    'renew_months' => $renewMonths,
                    'renew_days' => $renewDays,
                    'before_expire_time' => $beforeExpireTime ?: null,
                    'after_expire_time' => $afterExpireTime,
                    'amount' => $amount,
                    'remark' => $remark,
                    'renew_remind_days' => $renewRemindDays,
                    'create_uid' => $operatorUid,
                    'create_time' => $now,
                ]);
            }
            Db::commit();
        } catch (\Throwable $e) {
            Db::rollback();
            throw $e;
        }

        MerchantCache::del($ids);
        return [
            'ids' => $ids,
            'renew_months' => $renewMonths,
            'renew_days' => $renewDays,
            'amount' => $amount,
            'renew_remind_days' => $renewRemindDays,
            'adjust_title' => self::formatRenewDuration($renewMonths, $renewDays),
        ];
    }
    public static function renewRecordList($where = [], $page = 1, $limit = 10, $order = [], $field = '')
    {
        $model = new MerchantRenewRecordModel();
        if (empty($field)) {
            $field = 'r.id,r.merchant_id,r.member_id,r.operator_uid,r.renew_source,r.renew_months,r.renew_days,r.before_expire_time,r.after_expire_time,r.amount,r.remark,r.renew_remind_days,r.create_time,m.title as merchant_title';
        }
        if (empty($order)) {
            $order = ['r.id' => 'desc'];
        }
        $query = $model->alias('r')
            ->leftJoin('merchant m', 'm.id = r.merchant_id')
            ->where('r.is_delete', 0)
            ->field($field);
        foreach ($where as $item) {
            $query->where($item[0], $item[1], $item[2]);
        }
        $count = (clone $query)->count();
        $pages = $limit > 0 ? ceil($count / $limit) : 0;
        $list = [];
        if ($count > 0) {
            $list = $query->page($page)->limit($limit)->order($order)->select()->toArray();
            foreach ($list as $k => $v) {
                $list[$k]['renew_source_title'] = self::getRenewSourceTitle($v['renew_source'] ?? '');
                $list[$k]['adjust_title'] = self::formatRenewDuration($v['renew_months'] ?? 0, $v['renew_days'] ?? 0);
                $list[$k]['adjust_type'] = self::isReduceAdjust($v['renew_months'] ?? 0, $v['renew_days'] ?? 0) ? 'reduce' : 'increase';
                $list[$k]['adjust_type_title'] = $list[$k]['adjust_type'] === 'reduce' ? 'Reduce duration' : 'Increase duration';
            }
        }
        return compact('count', 'pages', 'page', 'limit', 'list');
    }

