    public static function info($id, $exce = true)
    {
        $info = MerchantCache::get($id);
        if (empty($info)) {
            $model = new MerchantModel();
            $info = $model->with(['image', 'files'])
                ->append(['image_url', 'receipt_image_url', 'images'])
                ->hidden(['image', 'files'])
                ->find($id);
            if (empty($info)) {
                if ($exce) {
                    exception('Merchant not found: ' . $id);
                }
                return [];
            }
            $info = $info->toArray();
            $info = self::appendExpireMeta($info);
            $info['member_is_super'] = self::supportsMemberSuperFlag() ? intval($info['member_is_super'] ?? 0) : 0;
            $info['member_is_super_title'] = intval($info['member_is_super'] ?? 0) === 1 ? '是' : '否';
            $info = MobileAdminAccessService::decorateMerchant($info);
            MerchantCache::set($id, $info);
        }
        $info['member_is_super'] = intval($info['member_is_super'] ?? 0);
        $info['member_is_super_title'] = intval($info['member_is_super'] ?? 0) === 1 ? '是' : '否';
        return MobileAdminAccessService::decorateMerchant($info);
    }

    public static function normalizePurchaseLimitFields(array &$param)
    {
        $quantityValue = $param['merchant_purchase_daily_quantity_limit'] ?? null;
        if ($quantityValue === '' || $quantityValue === null) {
            $param['merchant_purchase_daily_quantity_limit'] = null;
        } else {
            $quantity = intval($quantityValue);
            $param['merchant_purchase_daily_quantity_limit'] = $quantity > 0 ? $quantity : null;
        }

        $amountValue = $param['merchant_purchase_daily_amount_limit'] ?? null;
        if ($amountValue === '' || $amountValue === null) {
            $param['merchant_purchase_daily_amount_limit'] = null;
        } else {
            $amount = round(floatval($amountValue), 2);
            $param['merchant_purchase_daily_amount_limit'] = $amount > 0 ? $amount : null;
        }
    }

    public static function normalizeOptionalDateFields(array &$param)
    {
        if (array_key_exists('expire_time', $param)) {
            $expireTime = trim((string) $param['expire_time']);
            $param['expire_time'] = $expireTime !== '' ? $expireTime : null;
        }
