    public static function getInfoByMemberID()
    {
        $memberId = member_id();
        $model = new MerchantModel();
        $supportsMemberSuper = self::supportsMemberSuperFlag();
        $field = 'id,title,username,phone,auth_state,auth_msg,name,image_id,member_id,expire_time,renew_remind_days';
        if ($supportsMemberSuper) {
            $field .= ',member_is_super';
        }
        $info = $model->where('member_id', $memberId)
            ->append(['image_url', 'receipt_image_url', 'images'])
            ->hidden(['image', 'files'])
            ->field($field)
            ->find();
        if($info){
            $info = $info->toArray();
            $info = self::appendExpireMeta($info);
            $info = self::appendPendingWriteoffMeta($info);
            $info['auth_state_title'] = MerchantModel::getAuthState($info['auth_state'],2);
            $info['mer_host'] = rtrim(server_url(), '/') . '/merchant';
            $info['member_is_super'] = $supportsMemberSuper ? intval($info['member_is_super'] ?? 0) : 0;
            $info['merchant_system_super'] = $supportsMemberSuper
                ? intval($info['member_is_super'] ?? 0)
                : self::resolveLegacyMemberMerchantSuper($info, intval($memberId));
            $currentIdentity = MerchantIdentityService::current(intval($memberId), MerchantIdentityService::requestedMerUserId());
            $info['current_mer_user_id'] = intval($currentIdentity['identity']['mer_user_id'] ?? 0);
            $info['frontend_permission_codes'] = $currentIdentity['permissions']['permission_codes']
                ?? MerchantIdentityService::buildPermissionCodes($info);
        }
        return $info;
    }

    public static function assertMemberMerchantReleaseAllowed($memberId = null)
    {
        $memberId = $memberId ?: member_id(true);
        $info = self::getInfoByMemberID();
        if (empty($info)) {
            exception('请先完成商家入驻');
        }
        if (intval($info['auth_state'] ?? 0) === 0) {
            exception('商家审核中');
        }
        if (intval($info['auth_state'] ?? 0) === 2) {
            exception(trim((string) ($info['auth_msg'] ?? '')) ?: '商家审核未通过');
        }

        $availableMerchant = self::assertMemberMerchantAvailableIfExists($memberId);
        if (empty($availableMerchant)) {
            exception('请先完成商家入驻');
        }

        return $info;
    }

    public static function setMemberSuper($ids, int $memberIsSuper = 0): array
    {
        if (!self::supportsMemberSuperFlag()) {
            exception('请先执行商家超管字段补丁后再操作');
        }
        $ids = array_values(array_unique(array_filter(array_map('intval', (array) $ids))));
        if (empty($ids)) {
            exception('请选择商家');
        }

        $memberIsSuper = $memberIsSuper === 1 ? 1 : 0;
        $merchantList = MerchantModel::whereIn('id', $ids)
            ->where('is_delete', 0)
            ->field('id,title,member_id,member_is_super')
            ->select()
            ->toArray();
        if (empty($merchantList)) {
            exception('未找到可设置的商家');
        }

        if ($memberIsSuper === 1) {
            $missingMembers = [];
            foreach ($merchantList as $merchant) {
                if (intval($merchant['member_id'] ?? 0) <= 0) {
                    $missingMembers[] = trim((string) ($merchant['title'] ?? ('商家#' . intval($merchant['id'] ?? 0))));
                }
            }
            if (!empty($missingMembers)) {
                exception('以下商家尚未绑定会员，无法设置商家超管：' . implode('、', $missingMembers));
            }
        }

        MerchantModel::whereIn('id', $ids)->update([
            'member_is_super' => $memberIsSuper,
            'update_uid' => user_id(),
            'update_time' => datetime(),
        ]);

        MerchantCache::del($ids);

        return [
            'ids' => $ids,
            'member_is_super' => $memberIsSuper,
        ];
    }

    private static function supportsMemberSuperFlag(): bool
    {
        if (self::$hasMerchantMemberSuperColumn !== null) {
            return self::$hasMerchantMemberSuperColumn;
        }

        try {
            $dbName = Db::query('SELECT DATABASE() AS db_name');
            $dbName = strval($dbName[0]['db_name'] ?? '');
            if ($dbName === '') {
                self::$hasMerchantMemberSuperColumn = false;
                return false;
            }

            $rows = Db::query(
                "SELECT COUNT(*) AS total FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA = ? AND TABLE_NAME = 'ya_merchant' AND COLUMN_NAME = 'member_is_super'",
                [$dbName]
            );
            self::$hasMerchantMemberSuperColumn = intval($rows[0]['total'] ?? 0) > 0;
        } catch (\Throwable $e) {
            self::$hasMerchantMemberSuperColumn = false;
        }

        return self::$hasMerchantMemberSuperColumn;
    }

    private static function resolveLegacyMemberMerchantSuper(array $info = [], int $memberId = 0): int
    {
        $memberAccount = Db::name('member')
            ->where('member_id', $memberId)
            ->field('username,phone')
            ->find();
        $currentUsername = strval($memberAccount['username'] ?? '');
        $currentPhone = strval($memberAccount['phone'] ?? '');

        $superIds = array_map('intval', mer_user_super_ids());
        $adminUsers = MerchantUserModel::where('mer_id', intval($info['id'] ?? 0))
            ->where('is_delete', 0)
            ->where('is_disable', 0)
            ->where('is_admin', 1)
            ->field('mer_user_id,username,phone,is_super')
            ->select()
            ->toArray();

        foreach ($adminUsers as $adminUser) {
            $sameAccount = false;
            if ($currentUsername !== '' && strval($adminUser['username'] ?? '') === $currentUsername) {
                $sameAccount = true;
            }
            if ($currentPhone !== '' && strval($adminUser['phone'] ?? '') === $currentPhone) {
                $sameAccount = true;
            }

            if ($sameAccount && (
                intval($adminUser['is_super'] ?? 0) === 1 ||
                in_array(intval($adminUser['mer_user_id'] ?? 0), $superIds, true)
            )) {
                return 1;
            }
        }

        return 0;
    }

    /**
