     *
     * @param int $merchantId
     * @param int $days
     * @return array
     */
    public static function getAnalytics($merchantId, $param = [])
    {
        $param['merchant_id'] = $merchantId;
        $range = self::resolveAnalyticsRange($param);
        $days = $range['days'];
        $refundStatus = MemberOrderModel::getStatus('refund', 1);
        $merchant = MerchantModel::where('id', $merchantId)
            ->where('is_delete', 0)
            ->where('is_disable', 0)
            ->field('id,title,auth_state,create_time,member_id,expire_time,renew_remind_days')
            ->find();
        if (empty($merchant)) {
            exception('Merchant not found');
        }
        $merchant = self::appendExpireMeta($merchant->toArray());

        $todayStart = date('Y-m-d 00:00:00');
        $todayEnd = date('Y-m-d 23:59:59');
        $rangeStart = $range['start_time'];
        $rangeEnd = $range['end_time'];
        $merchantMemberId = intval($merchant['member_id'] ?? 0);

        $orderQuery = self::buildAnalyticsOrderDetailQuery($merchantId, $merchantMemberId);
        $paidOrderQuery = (clone $orderQuery)
            ->where('order_info.pay_status', 1)
            ->where('order_info.status', '<>', $refundStatus);
        $goodsQuery = GoodsModel::where('is_delete', 0)
            ->where('is_disable', 0);
        self::applyAnalyticsGoodsScope($goodsQuery, $merchantId, $merchantMemberId);
        $purchaseOrderQuery = self::buildAnalyticsPurchaseOrderQuery($merchantId, $merchantMemberId, $refundStatus);

        $orderCount = intval((clone $orderQuery)->distinct(true)->count('order_info.id'));
        $paidOrderCount = intval((clone $paidOrderQuery)->distinct(true)->count('order_info.id'));
        $paidAmount = self::toFloat((clone $paidOrderQuery)->sum('detail.total'));
        $purchaseOrderCount = $merchantMemberId > 0 ? (clone $purchaseOrderQuery)->count() : 0;
        $purchaseAmount = $merchantMemberId > 0 ? self::toFloat((clone $purchaseOrderQuery)->sum(Db::raw(self::analyticsPaidAmountExpression()))) : 0;
        $todayOrderCount = intval((clone $orderQuery)->whereBetweenTime('order_info.create_time', $todayStart, $todayEnd)->distinct(true)->count('order_info.id'));
        $todayPaidOrderCount = intval((clone $paidOrderQuery)->whereBetweenTime('order_info.pay_time', $todayStart, $todayEnd)->distinct(true)->count('order_info.id'));
        $todayPaidAmount = self::toFloat((clone $paidOrderQuery)->whereBetweenTime('order_info.pay_time', $todayStart, $todayEnd)->sum('detail.total'));
        $todayBuyerCount = intval((clone $paidOrderQuery)->whereBetweenTime('order_info.pay_time', $todayStart, $todayEnd)->distinct(true)->count('order_info.member_id'));
        $todayPurchaseAmount = $merchantMemberId > 0 ? self::toFloat((clone $purchaseOrderQuery)->whereBetweenTime('pay_time', $todayStart, $todayEnd)->sum(Db::raw(self::analyticsPaidAmountExpression()))) : 0;
        $todayPurchaseOrderCount = $merchantMemberId > 0 ? (clone $purchaseOrderQuery)->whereBetweenTime('pay_time', $todayStart, $todayEnd)->count() : 0;
        $goodsCount = (clone $goodsQuery)->count();
        $onSaleGoodsCount = (clone $goodsQuery)->where('status', 1)->where('stock', '>', 0)->count();
        $soldOutGoodsCount = (clone $goodsQuery)->where('status', 1)->where('stock', '<=', 0)->count();
        $pendingGoodsCount = (clone $goodsQuery)->where('status', 0)->count();

        $rangeOrderCount = intval((clone $orderQuery)->whereBetweenTime('order_info.create_time', $rangeStart, $rangeEnd)->distinct(true)->count('order_info.id'));
        $rangePaidOrderCount = intval((clone $paidOrderQuery)->whereBetweenTime('order_info.pay_time', $rangeStart, $rangeEnd)->distinct(true)->count('order_info.id'));
        $rangePaidAmount = self::toFloat((clone $paidOrderQuery)->whereBetweenTime('order_info.pay_time', $rangeStart, $rangeEnd)->sum('detail.total'));
        $rangeBuyerCount = intval((clone $paidOrderQuery)->whereBetweenTime('order_info.pay_time', $rangeStart, $rangeEnd)->distinct(true)->count('order_info.member_id'));
        $rangePurchaseAmount = $merchantMemberId > 0 ? self::toFloat((clone $purchaseOrderQuery)->whereBetweenTime('pay_time', $rangeStart, $rangeEnd)->sum(Db::raw(self::analyticsPaidAmountExpression()))) : 0;
        $rangePurchaseOrderCount = $merchantMemberId > 0 ? (clone $purchaseOrderQuery)->whereBetweenTime('pay_time', $rangeStart, $rangeEnd)->count() : 0;

        $statusRows = (clone $orderQuery)
            ->field('order_info.status as status, COUNT(DISTINCT order_info.id) as total')
            ->group('order_info.status')
            ->select()
            ->toArray();
        $statusMap = [];
        foreach ($statusRows as $row) {
            $statusMap[intval($row['status'])] = intval($row['total']);
        }
        $statusBreakdown = [];
        foreach (MemberOrderModel::STATUS as $status) {
            $count = $statusMap[$status['value']] ?? 0;
            $statusBreakdown[] = [
                'status' => $status['value'],
                'code' => $status['code'],
                'label' => $status['label'],
                'count' => $count,
                'rate' => $orderCount > 0 ? round(($count / $orderCount) * 100, 1) : 0,
            ];
        }

        $orderTrendRows = (clone $orderQuery)
            ->whereBetweenTime('order_info.create_time', $rangeStart, $rangeEnd)
            ->field("DATE_FORMAT(order_info.create_time,'%Y-%m-%d') as day, COUNT(DISTINCT order_info.id) as order_count")
            ->group("DATE_FORMAT(order_info.create_time,'%Y-%m-%d')")
            ->select()
            ->toArray();
        $paidTrendRows = (clone $paidOrderQuery)
            ->whereBetweenTime('order_info.pay_time', $rangeStart, $rangeEnd)
            ->field("DATE_FORMAT(order_info.pay_time,'%Y-%m-%d') as day, COUNT(DISTINCT order_info.id) as paid_order_count, SUM(detail.total) as paid_amount")
            ->group("DATE_FORMAT(order_info.pay_time,'%Y-%m-%d')")
            ->select()
            ->toArray();
        $purchaseTrendRows = $merchantMemberId > 0 ? (clone $purchaseOrderQuery)
            ->whereBetweenTime('pay_time', $rangeStart, $rangeEnd)
            ->field("DATE_FORMAT(pay_time,'%Y-%m-%d') as day, COUNT(id) as buy_order_count, SUM(" . self::analyticsPaidAmountExpression() . ") as buy_amount")
            ->group("DATE_FORMAT(pay_time,'%Y-%m-%d')")
            ->select()
            ->toArray() : [];
        $orderTrendMap = [];
        foreach ($orderTrendRows as $row) {
            $orderTrendMap[$row['day']] = intval($row['order_count']);
        }
        $paidTrendMap = [];
        foreach ($paidTrendRows as $row) {
            $paidTrendMap[$row['day']] = [
                'paid_order_count' => intval($row['paid_order_count']),
                'paid_amount' => self::toFloat($row['paid_amount'] ?? 0),
            ];
        }
        $purchaseTrendMap = [];
        foreach ($purchaseTrendRows as $row) {
            $purchaseTrendMap[$row['day']] = [
                'buy_order_count' => intval($row['buy_order_count']),
                'buy_amount' => self::toFloat($row['buy_amount'] ?? 0),
            ];
        }
        $trend = [];
        $trendEndDate = date('Y-m-d', strtotime($rangeEnd));
        $trendStartDate = date('Y-m-d', strtotime($rangeStart));
        for ($index = $days - 1; $index >= 0; $index--) {
            $day = date('Y-m-d', strtotime('-' . $index . ' days', strtotime($trendEndDate)));
            if (strtotime($day) < strtotime($trendStartDate)) {
                continue;
            }
            $trend[] = [
                'day' => $day,
                'label' => date('m-d', strtotime($day)),
                'order_count' => $orderTrendMap[$day] ?? 0,
                'paid_order_count' => $paidTrendMap[$day]['paid_order_count'] ?? 0,
                'paid_amount' => $paidTrendMap[$day]['paid_amount'] ?? 0,
                'buy_order_count' => $purchaseTrendMap[$day]['buy_order_count'] ?? 0,
                'buy_amount' => $purchaseTrendMap[$day]['buy_amount'] ?? 0,
            ];
        }

        $topGoodsRows = (clone $paidOrderQuery)
            ->whereBetweenTime('order_info.pay_time', $rangeStart, $rangeEnd)
            ->field('detail.goods_id, SUM(detail.quantity) as sale_num, SUM(detail.total) as sale_amount, COUNT(DISTINCT detail.member_order_id) as order_count')
            ->group('detail.goods_id')
            ->order('sale_amount desc, sale_num desc')
            ->limit(5)
            ->select()
            ->toArray();
        $goodsIds = array_column($topGoodsRows, 'goods_id');
        $goodsList = [];
        if (!empty($goodsIds)) {
            $goodsList = GoodsModel::whereIn('id', $goodsIds)
                ->with(['image'])
                ->append(['image_url'])
                ->hidden(['image'])
                ->field('id,title,image_id,source,unit')
                ->select()
                ->toArray();
        }
        $goodsMap = [];
        foreach ($goodsList as $goods) {
            $goodsMap[intval($goods['id'])] = $goods;
        }
        $topGoods = [];
        foreach ($topGoodsRows as $row) {
            $goodsId = intval($row['goods_id']);
            $goods = $goodsMap[$goodsId] ?? [];
            $topGoods[] = [
                'goods_id' => $goodsId,
                'title' => $goods['title'] ?? 'Deleted product',
                'image_url' => $goods['image_url'] ?? '',
                'unit' => $goods['unit'] ?? '',
                'sale_num' => intval($row['sale_num']),
                'sale_amount' => self::toFloat($row['sale_amount'] ?? 0),
                'order_count' => intval($row['order_count']),
            ];
        }

        $overview = [
            'order_count' => $orderCount,
            'paid_order_count' => $paidOrderCount,
            'paid_amount' => $paidAmount,
            'purchase_order_count' => $purchaseOrderCount,
            'purchase_amount' => $purchaseAmount,
            'purchase_paid_order_count' => $purchaseOrderCount,
            'purchase_paid_amount' => $purchaseAmount,
            'today_order_count' => $todayOrderCount,
            'today_paid_amount' => $todayPaidAmount,
            'today_buyer_count' => $todayBuyerCount,
            'today_purchase_order_count' => $todayPurchaseOrderCount,
            'today_purchase_amount' => $todayPurchaseAmount,
            'today_purchase_paid_order_count' => $todayPurchaseOrderCount,
            'today_purchase_paid_amount' => $todayPurchaseAmount,
            'goods_count' => $goodsCount,
            'on_sale_goods_count' => $onSaleGoodsCount,
            'sold_out_goods_count' => $soldOutGoodsCount,
            'pending_goods_count' => $pendingGoodsCount,
            'average_order_amount' => $paidOrderCount > 0 ? round($paidAmount / $paidOrderCount, 2) : 0,
        ];
        $rangeSummary = [
            'filter_type' => $range['filter_type'],
            'days' => $days,
            'month' => $range['month'],
            'start_date' => date('Y-m-d', strtotime($rangeStart)),
            'end_date' => date('Y-m-d', strtotime($rangeEnd)),
            'order_count' => $rangeOrderCount,
            'paid_order_count' => $rangePaidOrderCount,
            'paid_amount' => $rangePaidAmount,
            'buyer_count' => $rangeBuyerCount,
            'label' => $range['label'],
        ];
        $tradeComparison = [
            'range_buy_amount' => $rangePurchaseAmount,
            'range_buy_order_count' => $rangePurchaseOrderCount,
            'range_sale_amount' => $rangePaidAmount,
            'range_sale_order_count' => $rangePaidOrderCount,
            'range_diff_amount' => round($rangePaidAmount - $rangePurchaseAmount, 2),
            'range_diff_order_count' => intval($rangePaidOrderCount - $rangePurchaseOrderCount),
            'range_buy_to_sale_ratio' => $rangePaidAmount > 0 ? round(($rangePurchaseAmount / $rangePaidAmount) * 100, 1) : null,
            'today_diff_amount' => round($todayPaidAmount - $todayPurchaseAmount, 2),
            'today_diff_order_count' => intval($todayPaidOrderCount - $todayPurchaseOrderCount),
            'today_buy_to_sale_ratio' => $todayPaidAmount > 0 ? round(($todayPurchaseAmount / $todayPaidAmount) * 100, 1) : null,
            'total_buy_amount' => $purchaseAmount,
            'total_buy_order_count' => $purchaseOrderCount,
            'total_sale_amount' => $paidAmount,
            'total_sale_order_count' => $paidOrderCount,
            'total_diff_amount' => round($paidAmount - $purchaseAmount, 2),
            'total_diff_order_count' => intval($paidOrderCount - $purchaseOrderCount),
            'today_buy_amount' => $todayPurchaseAmount,
            'today_buy_order_count' => $todayPurchaseOrderCount,
            'today_sale_amount' => $todayPaidAmount,
            'today_sale_order_count' => $todayPaidOrderCount,
        ];

        return [
            'merchant' => [
                'id' => intval($merchant['id']),
                'title' => MerchantModel::formatDisplayTitle((string) ($merchant['title'] ?? '')),
                'auth_state' => intval($merchant['auth_state']),
                'auth_state_title' => MerchantModel::getAuthState($merchant['auth_state'], 2),
                'create_time' => $merchant['create_time'],
                'expire_time' => $merchant['expire_time'] ?? '',
                'renew_remind_days' => intval($merchant['renew_remind_days'] ?? self::DEFAULT_RENEW_REMIND_DAYS),
                'expire_status' => $merchant['expire_status'] ?? 'unset',
                'expire_status_title' => $merchant['expire_status_title'] ?? 'No expiry set',
                'is_expired' => intval($merchant['is_expired'] ?? 0),
                'days_left' => $merchant['days_left'] ?? null,
                'should_remind' => intval($merchant['should_remind'] ?? 0),
            ],
            'overview' => $overview,
            'range_summary' => $rangeSummary,
            'trade_comparison' => $tradeComparison,
            'status_breakdown' => $statusBreakdown,
            'trend' => $trend,
            'top_goods' => $topGoods,
        ];
    }

    private static function applyAnalyticsGoodsScope($query, int $merchantId, int $merchantMemberId, string $goodsAlias = '')
    {
        $prefix = $goodsAlias !== '' ? $goodsAlias . '.' : '';
        $merchantField = $prefix . 'merchant_id';
        $memberField = $prefix . 'member_id';

        $query->where(function ($scopeQuery) use ($merchantField, $memberField, $merchantId, $merchantMemberId) {
            $scopeQuery->where($merchantField, $merchantId);
            if ($merchantMemberId > 0) {
                $scopeQuery->whereOr(function ($platformQuery) use ($merchantField, $memberField, $merchantMemberId) {
                    $platformQuery->where($merchantField, 0)
                        ->where($memberField, $merchantMemberId);
                });
            }
        });

        return $query;
    }

    private static function buildAnalyticsOrderDetailQuery(int $merchantId, int $merchantMemberId)
    {
        $query = Db::name('member_order_detailed')
            ->alias('detail')
            ->join('member_order order_info', 'order_info.id = detail.member_order_id')
            ->join('goods goods', 'goods.id = detail.goods_id')
            ->where('order_info.is_delete', 0)
            ->where('order_info.is_disable', 0)
            ->where('goods.is_delete', 0)
            ->where('goods.is_disable', 0);

        self::applyAnalyticsGoodsScope($query, $merchantId, $merchantMemberId, 'goods');

        return $query;
    }

    private static function analyticsPaidAmountExpression(): string
    {
        return '(CASE WHEN pay_price > 0 THEN pay_price ELSE total_price END)';
    }

    private static function buildAnalyticsPurchaseOrderQuery(int $merchantId, int $merchantMemberId, int $refundStatus)
    {
        $query = Db::name('member_order')
            ->where('is_delete', 0)
            ->where('is_disable', 0);

        if ($merchantMemberId <= 0) {
            $query->where('id', 0);
            return $query;
        }

        $query->where('member_id', $merchantMemberId)
            ->where('merchant_id', '<>', $merchantId)
            ->where('pay_status', 1)
            ->where('status', '<>', $refundStatus);
        return $query;
    }
