    public static function edit($ids, $param = [])
    {
        $model = new MerchantModel();
        $pk = $model->getPk();
        $ids = is_array($ids)
            ? array_values(array_unique(array_filter(array_map('intval', $ids))))
            : [intval($ids)];
        $ids = array_values(array_filter($ids));
        if (empty($ids)) {
            exception('请选择商家');
        }
        $syncGoodsDisable = intval($param['sync_goods_disable'] ?? 0) === 1;
        $targetDisableValue = isset($param['is_disable']) ? intval($param['is_disable']) : null;
        $merchantListForGoodsSync = [];
        if ($syncGoodsDisable && $targetDisableValue === 1) {
            $merchantListForGoodsSync = $model->whereIn($pk, $ids)
                ->where('is_delete', 0)
                ->field('id,member_id')
                ->select()
                ->toArray();
        }
        unset($param[$pk], $param['ids'], $param['sync_goods_disable']);
        self::normalizeOptionalDateFields($param);
        self::normalizePurchaseLimitFields($param);
