    /**
     * 按商家归属批量下架商品。
     * 兼容 merchant_id 直连商品，以及 merchant_id=0 但 member_id 归属于商家的平台商品。
     *
     * @param array $merchantList
     * @return int
     */
    private static function disableMerchantGoodsByOwnership(array $merchantList = []): int
    {
        $merchantIds = array_values(array_unique(array_filter(array_map(function ($merchant) {
            return intval($merchant['id'] ?? 0);
        }, $merchantList))));
        $merchantMemberIds = array_values(array_unique(array_filter(array_map(function ($merchant) {
            return intval($merchant['member_id'] ?? 0);
        }, $merchantList))));

        if (empty($merchantIds) && empty($merchantMemberIds)) {
            return 0;
        }

        $query = GoodsModel::where('is_delete', 0)
            ->where(function ($goodsQuery) use ($merchantIds, $merchantMemberIds) {
                if (!empty($merchantIds)) {
                    $goodsQuery->whereIn('merchant_id', $merchantIds);
                }
                if (!empty($merchantMemberIds)) {
                    $method = !empty($merchantIds) ? 'whereOr' : 'where';
                    $goodsQuery->{$method}(function ($platformQuery) use ($merchantMemberIds) {
                        $platformQuery->where('merchant_id', 0)
                            ->whereIn('member_id', $merchantMemberIds);
                    });
                }
            });

        return intval($query->update([
            'is_disable' => 1,
            'update_uid' => user_id(),
            'update_time' => datetime(),
        ]));
    }

    public static function getCurrentMemberMerchant($allowExpired = true, $exce = true, $field = '')
    {
        if (empty($field)) {
            $field = 'id,title,auth_state,create_time,member_id,expire_time,renew_remind_days,merchant_purchase_daily_quantity_limit,merchant_purchase_daily_amount_limit';
        }

        $merchant = MerchantModel::where('member_id', member_id(true))
            ->where('is_disable', 0)
            ->where('is_delete', 0)
            ->where('auth_state', 1)
            ->field($field)
            ->find();

        if (!$merchant) {
            if ($exce) {
                exception('Merchant info not found');
            }
            return [];
        }

        $merchant = self::appendExpireMeta($merchant->toArray());
        if (!$allowExpired && intval($merchant['is_expired']) === 1) {
            exception(self::buildMerchantExpiredErrorMessage($merchant));
        }
        return $merchant;
    }

    public static function assertMemberMerchantAvailableIfExists($memberId = null)
    {
        $memberId = $memberId ?: member_id(true);
        $merchant = MerchantModel::where('member_id', $memberId)
            ->where('is_disable', 0)
            ->where('is_delete', 0)
            ->where('auth_state', 1)
            ->field('id,title,expire_time,renew_remind_days,merchant_purchase_daily_quantity_limit,merchant_purchase_daily_amount_limit')
            ->find();

        if (!$merchant) {
            return [];
        }

        $merchant = self::appendExpireMeta($merchant->toArray());
        if (intval($merchant['is_expired']) === 1) {
            exception(self::buildMerchantExpiredErrorMessage($merchant));
        }
        return $merchant;
    }


    public static function buildMerchantExpiredErrorMessage($merchant = [])
    {
        $expireTime = '';
        if (is_array($merchant) && !empty($merchant['expire_time'])) {
            $expireTime = trim((string)$merchant['expire_time']);
        }
        return self::MERCHANT_EXPIRED_ERROR_PREFIX . '|' . $expireTime;
    }
    public static function appendExpireMeta($merchant)
    {
        if (empty($merchant) || !is_array($merchant)) {
            return $merchant;
        }

        $merchant['expire_time'] = $merchant['expire_time'] ?? '';
        $merchant['renew_remind_days'] = self::normalizeRenewRemindDays($merchant['renew_remind_days'] ?? self::DEFAULT_RENEW_REMIND_DAYS);
        $merchant['expire_status'] = 'unset';
        $merchant['expire_status_title'] = $merchant['expire_status_title'] ?? '未设置期限';
        $merchant['is_expired'] = 0;
        $merchant['should_remind'] = 0;
        $merchant['days_left'] = null;

        if (empty($merchant['expire_time'])) {
            return $merchant;
        }

        $expireTimestamp = strtotime($merchant['expire_time']);
        if ($expireTimestamp === false) {
            return $merchant;
        }

        $diffSeconds = $expireTimestamp - time();
        $daysLeft = $diffSeconds >= 0
            ? intval(ceil($diffSeconds / 86400))
            : -intval(ceil(abs($diffSeconds) / 86400));

        $merchant['days_left'] = $daysLeft;
        if ($diffSeconds < 0) {
            $merchant['expire_status'] = 'expired';
            $merchant['expire_status_title'] = '已到期';
            $merchant['is_expired'] = 1;
            return $merchant;
        }

        if ($daysLeft <= intval($merchant['renew_remind_days'])) {
            $merchant['expire_status'] = 'remind';
            $merchant['expire_status_title'] = '即将到期';
            $merchant['should_remind'] = 1;
            return $merchant;
        }

        $merchant['expire_status'] = 'active';
        $merchant['expire_status_title'] = '正常有效';
        return $merchant;
    }

    public static function appendPendingWriteoffMeta($merchant)
    {
        if (empty($merchant) || !is_array($merchant) || empty($merchant['id'])) {
            return $merchant;
        }

        $voucherPayType = MemberOrderModel::getPayType('voucher', 1);
        $pendingQuery = MemberOrderModel::where('merchant_id', intval($merchant['id']))
            ->where('is_delete', 0)
            ->where('is_disable', 0)
            ->where('status', 0)
            ->where('pay_type', $voucherPayType)
            ->where('pay_status', '<>', 1);

        $merchant['pending_writeoff_count'] = intval((clone $pendingQuery)->count());
        $merchant['pending_writeoff_amount'] = round(floatval((clone $pendingQuery)->sum('total_price')), 2);
        $merchant['pending_writeoff_oldest_time'] = (clone $pendingQuery)->min('create_time') ?: '';
        return $merchant;
    }

    private static function normalizeRenewRemindDays($value)
    {
        $days = intval($value);
        return $days > 0 ? $days : self::DEFAULT_RENEW_REMIND_DAYS;
    }

    public static function getExpireStatusOptions()
    {
        return [
            ['value' => 'unset', 'label' => '未设置期限'],
            ['value' => 'active', 'label' => '正常有效'],
            ['value' => 'remind', 'label' => '即将到期'],
            ['value' => 'expired', 'label' => '已到期'],
        ];
    }

    private static function applyExpireStatusFilter($query, $expireStatus = '')
    {
        $expireStatus = trim((string) $expireStatus);
        if ($expireStatus === '') {
            return;
        }

        if ($expireStatus === 'unset') {
            $query->where(function ($subQuery) {
                $subQuery->whereNull('expire_time')->whereOr('expire_time', '');
            });
            return;
        }

        if ($expireStatus === 'expired') {
            $query->whereNotNull('expire_time')
                ->where('expire_time', '<>', '')
                ->where('expire_time', '<', datetime());
            return;
        }

        if ($expireStatus === 'remind') {
            $query->where('expire_time', '>=', datetime())
                ->where('expire_time', '<>', '')
                ->whereRaw('TIMESTAMPDIFF(DAY, NOW(), expire_time) <= IFNULL(NULLIF(renew_remind_days, 0), ' . self::DEFAULT_RENEW_REMIND_DAYS . ')');
            return;
        }

        if ($expireStatus === 'active') {
            $query->where('expire_time', '>', datetime())
                ->where('expire_time', '<>', '')
                ->whereRaw('TIMESTAMPDIFF(DAY, NOW(), expire_time) > IFNULL(NULLIF(renew_remind_days, 0), ' . self::DEFAULT_RENEW_REMIND_DAYS . ')');
        }
    }

    private static function calculateRenewExpireTime($beforeExpireTime, $renewMonths = 0, $renewDays = 0)
    {
        $renewMonths = intval($renewMonths);
        $renewDays = intval($renewDays);
        $hasReduce = self::isReduceAdjust($renewMonths, $renewDays);
        $baseTimestamp = time();
        if (!empty($beforeExpireTime)) {
            $beforeTimestamp = strtotime($beforeExpireTime);
            if ($beforeTimestamp !== false) {
                if ($hasReduce) {
                    $baseTimestamp = $beforeTimestamp;
                } elseif ($beforeTimestamp > $baseTimestamp) {
                    $baseTimestamp = $beforeTimestamp;
                }
            }
        }
        $timestamp = $baseTimestamp;
        if ($renewMonths !== 0) {
            $timestamp = strtotime(($renewMonths > 0 ? '+' : '') . $renewMonths . ' month', $timestamp);
        }
        if ($renewDays !== 0) {
            $timestamp = strtotime(($renewDays > 0 ? '+' : '') . $renewDays . ' day', $timestamp);
        }
        if ($timestamp === false) {
            exception('续期时间计算失败，请重试');
        }
        return date('Y-m-d H:i:s', $timestamp);
    }

    private static function getRenewSourceTitle($source = '')
    {
        $map = [
            'admin' => '后台续期',
            'user' => '商家续期',
            'manual' => '人工调整',
        ];
        return $map[$source] ?? '后台续期';
    }

    private static function isReduceAdjust($renewMonths = 0, $renewDays = 0)
    {
        return intval($renewMonths) < 0 || intval($renewDays) < 0;
    }

    private static function formatRenewDuration($renewMonths = 0, $renewDays = 0)
    {
        $renewMonths = intval($renewMonths);
        $renewDays = intval($renewDays);
        $segments = [];

        if ($renewMonths !== 0) {
            $segments[] = ($renewMonths > 0 ? '增加' : '减少') . abs($renewMonths) . '个月';
        }
        if ($renewDays !== 0) {
            $segments[] = ($renewDays > 0 ? '增加' : '减少') . abs($renewDays) . '天';
        }

        if (empty($segments)) {
            return '后台更新';
        }

        return implode('，', $segments);
