     *
     * @param string $startTime
     * @param string $endTime
     * @return int
     */
    private static function calcDays($startTime, $endTime)
    {
        $diff = strtotime($endTime) - strtotime($startTime);
        if ($diff <= 0) {
            return 1;
        }

        return intval(floor($diff / 86400)) + 1;
